sql:
SELECT COUNT(*) 
FROM risk_types 
WHERE risk_category = 'operational';

SELECT summary, recommendations 
FROM risk_reports 
WHERE report_status = 'published';

SELECT risk_category, COUNT(*) as category_count
FROM risk_types
GROUP BY risk_category;

SELECT risk_type_name, description, risk_category, criticality 
FROM risk_types 
WHERE risk_type_name = 'transportation' AND criticality = 'high';

external_knowledge:
- "ongoing concerns" refers to events with an 'active' status;
- "significant risk areas" are those with an assessment score of 70 or more;
- "evaluation summaries" include the assessment score and status;
- "severity of decisions" translates to the decision strength;
- "financial implications" refers to the cost of implementing decisions;
- "protective measures" are described by the mitigation strategy;
- "managing sectors" represent the responsible department for the mitigation plan;
- "current state of the mitigation actions" means the status of the plan;
- "approval officers" are the users who approved the mitigation plans.

sql:
SELECT DISTINCT users.full_name
FROM users
INNER JOIN risk_reports ON users.user_id = risk_reports.published_by;

SELECT rt.risk_type_name, re.event_name
FROM risk_types rt
INNER JOIN risk_events re ON rt.risk_type_id = re.risk_type_id;

SELECT ROUND(TAN(AVG(impact_coefficient)), 2) AS AverageTangentOfImpactCoefficient
FROM risk_events
WHERE risk_source = 'external';

SELECT DISTINCT u.user_id, u.username, u.full_name
FROM users u
JOIN risk_assessments ra ON u.user_id = ra.assessor_id;
